import styled, { keyframes } from "styled-components";
import { useNavigate } from "react-router-dom";
import Slider from "../Components/Silder";
import Celular from "../Assets/Imagens/Celular_preto.png"
import Headfone from "../Assets/Imagens/Headfone_preto.png"
import Notebook from "../Assets/Imagens/Notebook.png"
import Smart from "../Assets/Imagens/Smartwatch_preto.png"

const categories = [
  { id: 1, title: "Celular", image: Celular, slug: "celular" },
  { id: 2, title: "Headphone", image: Headfone, slug: "headphone" },
  { id: 3, title: "Notebook", image: Notebook, slug: "notebook" },
  { id: 4, title: "Acessórios", image: Smart, slug: "acessorios" }
];


// Componente funcional Home
const Home = () => {
  const navigate = useNavigate();

  const handleCategoryClick = (slug) => {
    navigate(`/produtos?categoria=${slug}`);
  };

  return(
    <>
    <Container>
    
      <Slider/>
      <CategoriesSection>
        {categories.map((item) => (
          <CategoryCard key={item.id} onClick={() => handleCategoryClick(item.slug)}>
            <CategoryImage src={item.image} alt={item.title}></CategoryImage>
            <CategoryTitle>{item.title}</CategoryTitle>
          </CategoryCard>
        ))}
      </CategoriesSection>
      <WeekSection>
      <WeekContent>
      
        <WeekInfo>
          <WeekTag>Produto da Semana</WeekTag>
          <WeekTitle>Notebook Ultra X Pro</WeekTitle>
          <WeekDescription>
            Performance extrema, design minimalista e tecnologia de última geração
            para quem exige o máximo.
          </WeekDescription>
          <WeekPrice>R$ 5.499,90</WeekPrice>
          <WeekButton>Comprar Agora</WeekButton>
        </WeekInfo>
      </WeekContent>
    </WeekSection>

    <AdvantagesSection>
  <AdvantagesGrid>

    <AdvCard>
      <AdvIcon>🚚</AdvIcon>
      <AdvTitle>Frete Rápido</AdvTitle>
      <AdvText>Entrega para todo o Brasil com envio imediato.</AdvText>
    </AdvCard>

    <AdvCard>
      <AdvIcon>💳</AdvIcon>
      <AdvTitle>Pagamento Seguro</AdvTitle>
      <AdvText>Ambiente 100% protegido e criptografado.</AdvText>
    </AdvCard>

    <AdvCard>
      <AdvIcon>🛡</AdvIcon>
      <AdvTitle>Garantia Oficial</AdvTitle>
      <AdvText>Produtos com garantia e suporte especializado.</AdvText>
    </AdvCard>

    <AdvCard>
      <AdvIcon>⭐</AdvIcon>
      <AdvTitle>Qualidade Premium</AdvTitle>
      <AdvText>Selecionamos apenas as melhores marcas.</AdvText>
    </AdvCard>

  </AdvantagesGrid>
</AdvantagesSection>


    </Container>
    </>

  );
};


// Container principal
const Container = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  background-color: #f5f5f5;
`;

const fadeUp = keyframes`
  from {
    opacity: 0;
    transform: translateY(40px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
`;

const CategoriesSection = styled.section`
  display: flex;
  justify-content: center;
  gap: 40px;
  padding: 10px 0px;
  width: 100%;
  background: #0D0D0D;
`;

const CategoryCard = styled.div`
  position: relative;
  width: 300px;
  height: 180px;
  background: #1A1A1A;
  border-radius: 20px;
  display: flex;
  align-items: flex-end;
  justify-content: center;
  padding-bottom: 20px;
  cursor: pointer;
  overflow: visible;
  transition: 0.3s ease;
  animation: ${fadeUp} 0.8s ease forwards;

  &:hover {
    transform: translateY(-10px);
    background: #222;
  }
`;

const CategoryImage = styled.img`
  position: absolute;
  top: -40px;
  width: 140px;
  object-fit: contain;
  z-index: 1;
  transition: 0.3s ease;
  filter: drop-shadow(0 10px 25px rgba(124, 58, 237, 0.4));

  ${CategoryCard}:hover & {
    transform: scale(1.08);
  }
`;

const CategoryTitle = styled.h3`
  position: relative;
  z-index: 2;
  color: white;
  font-size: 18px;
  font-weight: 600;
  font-family: "Space Grotesk";
`;

const WeekSection = styled.section`
  width: 100%;
  background: #111;
  padding: 100px 10%;
  display: flex;
  justify-content: center;
`;

const WeekContent = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: 1200px;
  width: 100%;
  gap: 60px;
`;

const WeekImage = styled.img`
  width: 450px;
  object-fit: contain;
  filter: drop-shadow(0 20px 40px rgba(124, 58, 237, 0.5));
  animation: ${fadeUp} 1s ease forwards;
`;

const WeekInfo = styled.div`
  max-width: 500px;
  color: white;
`;

const WeekTag = styled.span`
  color: #7C3AED;
  font-weight: 600;
  letter-spacing: 2px;
  text-transform: uppercase;
  font-size: 14px;
`;

const WeekTitle = styled.h2`
  font-size: 42px;
  margin: 20px 0;
  font-family: "Orbitron", sans-serif;
`;

const WeekDescription = styled.p`
  color: #aaa;
  line-height: 1.6;
  margin-bottom: 20px;
`;

const WeekPrice = styled.h3`
  font-size: 28px;
  margin-bottom: 30px;
`;

const WeekButton = styled.button`
  padding: 14px 40px;
  background: linear-gradient(90deg, #7C3AED, #9333EA);
  border: none;
  border-radius: 40px;
  color: white;
  font-weight: bold;
  cursor: pointer;
  transition: 0.3s ease;

  &:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 30px rgba(124, 58, 237, 0.5);
  }
`;
const AdvantagesSection = styled.section`
  width: 100%;
  background: #0D0D0D;
  padding: 100px 10%;
  display: flex;
  justify-content: center;
`;

const AdvantagesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 40px;
  max-width: 1200px;
  width: 100%;
`;

const AdvCard = styled.div`
  background: #1A1A1A;
  padding: 40px 20px;
  border-radius: 20px;
  text-align: center;
  transition: 0.3s ease;
  cursor: pointer;

  &:hover {
    background: #7C3AED;
    transform: translateY(-8px);
  }
`;

const AdvIcon = styled.div`
  font-size: 40px;
  margin-bottom: 20px;
`;

const AdvTitle = styled.h4`
  font-size: 18px;
  margin-bottom: 10px;
  color: white;
  font-family: "Space Grotesk";
`;

const AdvText = styled.p`
  font-size: 14px;
  color: #ccc;
`;


export default Home;
